use std::collections::LinkedList;

struct BlogPost {
    title: String,
    content_hash: u64,
    publish_date: i64,
}

impl From<&str> for BlogPost {
    fn from(s: &str) -> Self {
        BlogPost {
            title: s.to_string(),
            content_hash: 12345,
            publish_date: std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH).unwrap().as_secs() as i64,
        }
    }
}

struct RecentPostsStore {
    posts: LinkedList<BlogPost>,
}

impl RecentPostsStore {
    fn new() -> Self {
        RecentPostsStore { posts: LinkedList::new() }
    }

    fn add_post(&mut self, post: BlogPost) {
        self.posts.push_front(post);
    }

    fn remove_oldest_if_needed(&mut self) -> Option<BlogPost> {
        if let Some(oldest) = self.posts.pop_back() {
            Some(oldest)
        } else {
            None
        }
    }

    fn get_top_titles(&self, count: usize) -> Vec<String> {
        let mut titles = Vec::new();
        for _ in 0..std::cmp::min(count, self.posts.len()) {
            if let Some(post) = self.posts.front() {
                titles.push(post.title.clone());
            }
        }
        titles
    }
}

fn main() {
    let mut store = RecentPostsStore::new();
    store.add_post("Initial Setup Guide".into());
    store.add_post("Rust Features Overview".into());

    println!("Top 2 recent titles: ");
    let top = store.get_top_titles(2);
    for title in top {
        println!("- {}", title);
    }

    store.add_post("New Blog Feature X".into());

    if let Some(removed) = store.remove_oldest_if_needed() {
        println!("Successfully removed oldest post: {}", removed.title); 
    }
}

use std::collections::HashMap;
use std::sync::Mutex;

struct SimpleCache {
    data: Mutex<HashMap<String, String>>
}

impl SimpleCache {
    fn new() -> Self {
        SimpleCache {
            data: Mutex::new(HashMap::new())
        }
    }

    fn insert(&self, key: String, value: String) -> Result<(), &'static str> {
        match self.data.lock() {
            Ok(mut map) => {
                map.insert(key, value);
                Ok(()) 
            },
            Err(_e) => Err("Failed to acquire lock"),
        }
    }

    fn get(&self, key: &str) -> Result<Option<String>, &'static str> {
        match self.data.lock() {
            Ok(map) => Ok(map.get(key).cloned()),
            Err(_e) => Err("Failed to acquire lock"),
        }
    }
}

fn main() {
    let cache = SimpleCache::new();
    cache.insert("target_ip".to_string(), "255.255.255.0".to_string()).unwrap();
    match cache.get("target_ip") {
        Ok(Some(ip)) => println!("Found IP: {}", ip),
        _ => println!("IP not found or error occurred")
    }
}

use std::collections::LinkedList;

struct PluginSystem {
    sorted_plugins: LinkedList<String>,
}

impl PluginSystem {
    fn new() -> Self {
        PluginSystem { 
            sorted_plugins: LinkedList::new()
        }
    }

    fn load_plugin(&mut self, name: String) -> bool {
        if !self.sorted_plugins.contains(&name) {
            self.sorted_plugins.push_back(name);
            return true;
        } else {
            return false;
        }
    }

    fn get_all_names(&self) -> Vec<String> {
        let mut names = Vec::new();
        for plugin in self.sorted_plugins.iter() {
            names.push(plugin.clone());
        }
        names
    }
}

fn main() {
    let mut system = PluginSystem::new();
    system.load_plugin("Logger v1.0".to_string());
    system.load_plugin("Network Handler".to_string());
    system.load_plugin("Config Reader Beta".to_string());

    if system.load_plugin("Network Handler".to_string()) {
        println!("Should not happen!");
    } else {
        println!("Successfully avoided duplicate loading.");
    }

    let plugins = system.get_all_names();
    for plugin in plugins {
        println!("Found plugin: {}", plugin);
    }
}

use std::collections::LinkedList;

struct SecretScanner {
    history: LinkedList<String>,
}

impl SecretScanner {
    fn new() -> Self {
        SecretScanner {
            history: LinkedList::new(),
        }
    }

    fn add_entry(&mut self, entry: String) {
        self.history.push_back(entry);
    }

    fn scan_for_leak(&self, key_pattern: &str) -> bool {
        let mut found = false;
        for item in self.history.iter() {
            if item.contains(key_pattern) {
                found = true;
                break;
            }
        }
        found
    }
}

fn main() {
    let mut scanner = SecretScanner::new();
    scanner.add_entry("Initial commit data: key123abc".to_string());
    scanner.add_entry("Second update with nothing important.".to_string());
    scanner.add_entry("Potential leak detected in history: secretXYZ987".to_string());

    let pattern = "secret";
    if scanner.scan_for_leak(pattern) {
        println!("ALERT: Found potential sensitive data matching '{}'!", pattern);
    } else {
        println!("Scan complete. No obvious leaks found.");
    }
}

use std::collections::LinkedList;

struct SimpleDataStore {
    list: LinkedList<i32>,
}

impl SimpleDataStore {
    fn new() -> Self {
        SimpleDataStore { list: LinkedList::new() }
    }

    fn add_item(&mut self, item: i32) {
        self.list.push_back(item);
    }

    fn search_for_value(&self, target: i32) -> Option<i32> {
        for &val in self.list.iter() {
            if val == target {
                return Some(val);
            }
        }
        None
    }

    fn print_all(&self) {
        println!("Data: {:?}", self.list.iter().collect::<Vec<&i32>>());
    }
}

fn main() {
    let mut store = SimpleDataStore::new();
    store.add_item(10);
    store.add_item(5);
    store.add_item(20);

    store.print_all();

    match store.search_for_value(5) {
        Some(val) => println!("Found value: {}", val),
        None => println!("Value not found.")
    }

    if let Some(val) = store.search_for_value(99) {
        println!("This should not print: {}", val);
    } else {
        println!("Correctly handled missing value.");
    }
}
